import React, {useState, useRef} from 'react'
import styled from 'styled-components'

const SidebarTitles = styled.div `
font-size:1.2rem;
font-weight:700;
`


export default function SideBarTitles ({handleToggle, children}) {

	const handleClick = () => {
		handleToggle()
	}

	return (
		<SidebarTitles onClick={handleClick}>{children}</SidebarTitles>
	)
}
